import { useState, useEffect, useMemo, useCallback, useRef } from "react";

// ─── Supabase credentials (set these in Replit Secrets, not here) ─────────────
const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL || "";
const SUPABASE_ANON_KEY = import.meta.env.VITE_SUPABASE_ANON_KEY || "";

// ─── Supabase storage layer ───────────────────────────────────────────────────
async function supabaseFetch(method, path, body) {
  if (!SUPABASE_URL) { console.error("Missing SUPABASE_URL"); return null; }
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    method,
    headers: {
      apikey: SUPABASE_ANON_KEY,
      Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
      "Content-Type": "application/json",
      Prefer: method === "POST" ? "resolution=merge-duplicates" : "",
    },
    body: body ? JSON.stringify(body) : undefined,
  });
  if (res.status === 204) return null;
  if (!res.ok) throw new Error(await res.text());
  return res.json();
}
async function storeSet(key, val) {
  try { await supabaseFetch("POST", "crm_store", { key, value: JSON.stringify(val) }); }
  catch (e) { console.error("storeSet error", e); }
}

