function simpleHash(s){let h=0;for(let c of s){h=((h<<5)-h)+c.charCodeAt(0);h|=0;}return h.toString(36);}
function uid(){return Date.now().toString(36)+Math.random().toString(36).slice(2);}
function fmt(v){return typeof v==="number"?v.toLocaleString("en-EU",{minimumFractionDigits:0,maximumFractionDigits:0}):"0";}
function fmtEur(v){return "€"+fmt(v);}
function fmtPct(v){return v?`${(v*100).toFixed(1)}%`:"—";}
function daysUntil(d){if(!d)return null;const diff=new Date(d)-new Date();return Math.round(diff/86400000);}
function isOverdue(d){const n=daysUntil(d);return n!==null&&n<0;}

