// ─── Storage helpers ──────────────────────────────────────────────────────────

// ─── App Root ─────────────────────────────────────────────────────────────────
export default function App(){
  const [currentUser,setCurrentUser]=useState(null);
  const [leads,setLeads]=useState([]);
  const [users,setUsers]=useState([]);
  const [view,setView]=useState("dashboard");
  const [modalLead,setModalLead]=useState(null);
  const [modalOpen,setModalOpen]=useState(false);
  const [loading,setLoading]=useState(true);

  // Load data on mount
  useEffect(()=>{
    (async()=>{
      // Users
      let u=await storeGet("crm:users",true);
      if(!u||u.length===0){u=DEFAULT_USERS;await storeSet("crm:users",u,true);}
      setUsers(u);
      // Leads
      let l=await storeGet("crm:leads",true);
      if(!l||l.length===0){
        l=SEED_LEADS.map(x=>({...x,tasks:[],activityLog:[]}));
        await storeSet("crm:leads",l,true);
      }
      setLeads(l);
      setLoading(false);
    })();
  },[]);

  const saveLeads=useCallback(async(newLeads)=>{
    setLeads(newLeads);
    await storeSet("crm:leads",newLeads,true);
  },[]);
  const saveUsers=useCallback(async(newUsers)=>{
    setUsers(newUsers);
    await storeSet("crm:users",newUsers,true);
  },[]);

  const openLead=useCallback((lead)=>{setModalLead(lead||{id:uid(),quoteNr:"",reference:"",version:"V1",rsm:"",client:"",poultry:"Broiler",sum:0,margin:0,status:"Orientation",likelihood:0.5,notes:"",manage:"",feeding1:"",feeding2:"",watering:"",controls:"",birdWeighing:"",flexAuger1:"",flexAuger2:"",silo1:"",silo2:"",ventilation:"",padCooling:"",feedWeighing:"",heating:"",aviary:"",cage:"",nest:"",country:"",dueDate:"",date:"",tasks:[],activityLog:[],createdAt:new Date().toISOString().slice(0,10)});setModalOpen(true);},[]);
  const closeLead=useCallback(()=>{setModalOpen(false);setModalLead(null);},[]);

  const saveLead=useCallback((lead)=>{
    const next=leads.some(l=>l.id===lead.id)?leads.map(l=>l.id===lead.id?lead:l):[...leads,lead];
    saveLeads(next);
    closeLead();
  },[leads,saveLeads,closeLead]);

  const deleteLead=useCallback((id)=>{
    if(confirm("Delete this lead?")){saveLeads(leads.filter(l=>l.id!==id));closeLead();}
  },[leads,saveLeads,closeLead]);

  if(loading)return <div style={{display:"flex",alignItems:"center",justifyContent:"center",height:"100vh",background:"#0f172a",color:"#94a3b8",fontFamily:"system-ui",fontSize:14}}>Loading CRM data…</div>;
  if(!currentUser)return <LoginPage users={users} onLogin={setCurrentUser}/>;

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100vh",background:"#f1f5f9",fontFamily:"'DM Sans',system-ui,sans-serif",color:"#1e293b",overflow:"hidden"}}>
      <NavBar view={view} setView={setView} currentUser={currentUser} onLogout={()=>setCurrentUser(null)}/>
      <div style={{flex:1,overflow:"auto",padding:"24px 32px"}}>
        {view==="dashboard"&&<Dashboard leads={leads} currentUser={currentUser}/>}
        {view==="pipeline"&&<Pipeline leads={leads} saveLeads={saveLeads} onOpen={openLead} currentUser={currentUser}/>}
        {view==="leads"&&<LeadsTable leads={leads} onOpen={openLead} currentUser={currentUser}/>}
        {view==="tasks"&&<TasksView leads={leads} saveLeads={saveLeads} currentUser={currentUser} onOpen={openLead}/>}
        {view==="settings"&&currentUser.role==="admin"&&<SettingsView users={users} saveUsers={saveUsers} currentUser={currentUser}/>}
      </div>
      {modalOpen&&<LeadModal lead={modalLead} onSave={saveLead} onClose={closeLead} onDelete={deleteLead} currentUser={currentUser}/>}
    </div>
  );
}

// ─── Login ────────────────────────────────────────────────────────────────────
function LoginPage({users,onLogin}){
  const [username,setUsername]=useState("");
  const [password,setPassword]=useState("");
  const [error,setError]=useState("");
  const login=()=>{
    const u=users.find(u=>u.username===username.trim()&&u.password===simpleHash(password));
    if(u){onLogin(u);setError("");}else setError("Invalid username or password");
  };
  return(
    <div style={{display:"flex",alignItems:"center",justifyContent:"center",minHeight:"100vh",background:"linear-gradient(135deg,#0f172a 0%,#1e3a5f 100%)"}}>
      <div style={{background:"#1e293b",borderRadius:16,padding:"48px 40px",width:380,boxShadow:"0 24px 60px rgba(0,0,0,0.5)"}}>
        <div style={{marginBottom:32,textAlign:"center"}}>
          <div style={{fontSize:28,fontWeight:800,color:"#f8fafc",letterSpacing:-0.5}}>🐔 Lead Manager</div>
          <div style={{fontSize:14,color:"#64748b",marginTop:6}}>Sign in to your account</div>
        </div>
        <div style={{marginBottom:16}}>
          <label style={{display:"block",fontSize:13,fontWeight:600,color:"#94a3b8",marginBottom:6}}>USERNAME</label>
          <input value={username} onChange={e=>setUsername(e.target.value)} onKeyDown={e=>e.key==="Enter"&&login()} style={{width:"100%",boxSizing:"border-box",padding:"10px 14px",borderRadius:8,border:"1px solid #334155",background:"#0f172a",color:"#f8fafc",fontSize:14,outline:"none"}} placeholder="e.g. paul.janssen"/>
        </div>
        <div style={{marginBottom:24}}>
          <label style={{display:"block",fontSize:13,fontWeight:600,color:"#94a3b8",marginBottom:6}}>PASSWORD</label>
          <input type="password" value={password} onChange={e=>setPassword(e.target.value)} onKeyDown={e=>e.key==="Enter"&&login()} style={{width:"100%",boxSizing:"border-box",padding:"10px 14px",borderRadius:8,border:"1px solid #334155",background:"#0f172a",color:"#f8fafc",fontSize:14,outline:"none"}} placeholder="••••••••"/>
        </div>
        {error&&<div style={{background:"#450a0a",color:"#fca5a5",borderRadius:8,padding:"10px 14px",fontSize:13,marginBottom:16}}>{error}</div>}
        <button onClick={login} style={{width:"100%",padding:"12px",background:"#3b82f6",color:"#fff",border:"none",borderRadius:8,fontWeight:700,fontSize:14,cursor:"pointer"}}>Sign In</button>
        <div style={{marginTop:24,padding:"16px",background:"#0f172a",borderRadius:8,fontSize:12,color:"#64748b"}}>
          <div style={{fontWeight:700,color:"#94a3b8",marginBottom:8}}>Default credentials (all: Lead2024!)</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:4}}>
            {["paul.janssen","daniel.sanz","chinedu.onuegbu","ahmed.abdou","zbigniew.myslinksi","internal.sales"].map(u=><span key={u} style={{color:"#60a5fa"}}>{u}</span>)}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── NavBar ───────────────────────────────────────────────────────────────────
function NavBar({view,setView,currentUser,onLogout}){
  const navItems=[{id:"dashboard",label:"Dashboard",icon:"📊"},{id:"pipeline",label:"Pipeline",icon:"🏆"},{id:"leads",label:"Leads",icon:"📋"},{id:"tasks",label:"Tasks",icon:"✅"}];
  if(currentUser.role==="admin")navItems.push({id:"settings",label:"Settings",icon:"⚙️"});
  return(
    <div style={{background:"#0f172a",color:"#f8fafc",padding:"0 24px",display:"flex",alignItems:"center",gap:4,height:56,flexShrink:0,borderBottom:"1px solid #1e293b"}}>
      <div style={{fontSize:16,fontWeight:800,color:"#f8fafc",marginRight:24,whiteSpace:"nowrap"}}>🐔 Lead Manager</div>
      {navItems.map(n=>(
        <button key={n.id} onClick={()=>setView(n.id)} style={{background:view===n.id?"#1e3a5f":"transparent",color:view===n.id?"#60a5fa":"#94a3b8",border:"none",borderRadius:8,padding:"6px 14px",cursor:"pointer",fontSize:13,fontWeight:600,display:"flex",alignItems:"center",gap:6}}>
          <span>{n.icon}</span>{n.label}
        </button>
      ))}
      <div style={{flex:1}}/>
      <div style={{fontSize:13,color:"#64748b",marginRight:12}}>{currentUser.fullName}</div>
      <button onClick={onLogout} style={{background:"#1e293b",color:"#94a3b8",border:"none",borderRadius:8,padding:"6px 12px",cursor:"pointer",fontSize:12,fontWeight:600}}>Sign out</button>
    </div>
  );
}

// ─── Dashboard ────────────────────────────────────────────────────────────────
function Dashboard({leads,currentUser}){
  const active=leads.filter(l=>!["Closed won","Closed lost"].includes(l.status));
  const closedWon=leads.filter(l=>l.status==="Closed won");
  const totalPipeline=active.reduce((s,l)=>s+(l.sum||0),0);
  const weighted=active.reduce((s,l)=>s+(l.sum||0)*(l.likelihood||0),0);
  const wonRevenue=closedWon.reduce((s,l)=>s+(l.sum||0),0);
  const overdueTasks=leads.flatMap(l=>(l.tasks||[]).filter(t=>!t.done&&t.dueDate&&daysUntil(t.dueDate)<0));

  const byStage=STATUS_STAGES.map(s=>{
    const sl=leads.filter(l=>l.status===s);
    return{stage:s,count:sl.length,value:sl.reduce((a,l)=>a+(l.sum||0),0)};
  });
  const byRSM=RSM_LIST.map(r=>{
    const rl=active.filter(l=>l.rsm===r);
    return{rsm:r,count:rl.length,value:rl.reduce((a,l)=>a+(l.sum||0),0)};
  }).filter(r=>r.count>0);

  const kpis=[
    {label:"Total Leads",value:leads.length,icon:"📋",color:"#3b82f6"},
    {label:"Active Pipeline",value:fmtEur(totalPipeline),icon:"💰",color:"#10b981"},
    {label:"Weighted Forecast",value:fmtEur(weighted),icon:"📈",color:"#8b5cf6"},
    {label:"Won Revenue",value:fmtEur(wonRevenue),icon:"🏆",color:"#f59e0b"},
  ];
  return(
    <div>
      <h2 style={{fontSize:22,fontWeight:800,marginBottom:24,margin:"0 0 24px"}}>Dashboard</h2>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:16,marginBottom:28}}>
        {kpis.map(k=>(
          <div key={k.label} style={{background:"#fff",borderRadius:12,padding:20,boxShadow:"0 1px 4px rgba(0,0,0,0.07)",borderLeft:`4px solid ${k.color}`}}>
            <div style={{fontSize:24,marginBottom:8}}>{k.icon}</div>
            <div style={{fontSize:22,fontWeight:800,color:"#1e293b"}}>{k.value}</div>
            <div style={{fontSize:13,color:"#64748b",marginTop:4}}>{k.label}</div>
          </div>
        ))}
      </div>
      {overdueTasks.length>0&&<div style={{background:"#fef2f2",border:"1px solid #fecaca",borderRadius:10,padding:"12px 16px",marginBottom:24,color:"#b91c1c",fontSize:13,fontWeight:600}}>⚠️ {overdueTasks.length} overdue task{overdueTasks.length>1?"s":""} need attention</div>}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:24}}>
        <div style={{background:"#fff",borderRadius:12,padding:20,boxShadow:"0 1px 4px rgba(0,0,0,0.07)"}}>
          <div style={{fontSize:15,fontWeight:700,marginBottom:16}}>Pipeline by Stage</div>
          {byStage.map(s=>{
            const maxVal=Math.max(...byStage.map(x=>x.value),1);
            const pct=Math.round(s.value/maxVal*100);
            return(
              <div key={s.stage} style={{marginBottom:12}}>
                <div style={{display:"flex",justifyContent:"space-between",fontSize:13,marginBottom:4}}>
                  <span style={{display:"flex",alignItems:"center",gap:8}}><span style={{width:10,height:10,borderRadius:"50%",background:STATUS_BADGE[s.stage],display:"inline-block"}}/>{s.stage}</span>
                  <span style={{color:"#64748b"}}>{s.count} · {fmtEur(s.value)}</span>
                </div>
                <div style={{background:"#f1f5f9",borderRadius:4,height:6}}><div style={{background:STATUS_BADGE[s.stage],height:6,borderRadius:4,width:`${pct}%`,transition:"width 0.3s"}}/></div>
              </div>
            );
          })}
        </div>
        <div style={{background:"#fff",borderRadius:12,padding:20,boxShadow:"0 1px 4px rgba(0,0,0,0.07)"}}>
          <div style={{fontSize:15,fontWeight:700,marginBottom:16}}>Active Pipeline by RSM</div>
          {byRSM.length===0?<div style={{color:"#94a3b8",fontSize:13}}>No active leads</div>:byRSM.sort((a,b)=>b.value-a.value).map(r=>{
            const maxVal=Math.max(...byRSM.map(x=>x.value),1);
            const pct=Math.round(r.value/maxVal*100);
            const short=r.rsm.split(" ").slice(0,2).join(" ");
            return(
              <div key={r.rsm} style={{marginBottom:12}}>
                <div style={{display:"flex",justifyContent:"space-between",fontSize:13,marginBottom:4}}>
                  <span>{short}</span>
                  <span style={{color:"#64748b"}}>{r.count} leads · {fmtEur(r.value)}</span>
                </div>
                <div style={{background:"#f1f5f9",borderRadius:4,height:6}}><div style={{background:"#3b82f6",height:6,borderRadius:4,width:`${pct}%`,transition:"width 0.3s"}}/></div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ─── Pipeline (Kanban) ────────────────────────────────────────────────────────
function Pipeline({leads,saveLeads,onOpen,currentUser}){
  const [filterRSM,setFilterRSM]=useState("");
  const filtered=filterRSM?leads.filter(l=>l.rsm===filterRSM):leads;
  const moveStatus=useCallback((lead,newStatus)=>{
    saveLeads(leads.map(l=>l.id===lead.id?{...l,status:newStatus,activityLog:[...(l.activityLog||[]),{id:uid(),text:`Status changed to ${newStatus}`,user:currentUser.fullName,timestamp:new Date().toISOString()}]}:l));
  },[leads,saveLeads,currentUser]);

  return(
    <div>
      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:20}}>
        <h2 style={{fontSize:22,fontWeight:800,margin:0}}>Sales Pipeline</h2>
        <div style={{flex:1}}/>
        <select value={filterRSM} onChange={e=>setFilterRSM(e.target.value)} style={{padding:"6px 12px",borderRadius:8,border:"1px solid #e2e8f0",background:"#fff",fontSize:13,color:"#1e293b"}}>
          <option value="">All RSMs</option>
          {RSM_LIST.map(r=><option key={r}>{r}</option>)}
        </select>
        <button onClick={()=>onOpen(null)} style={{background:"#3b82f6",color:"#fff",border:"none",borderRadius:8,padding:"8px 16px",fontWeight:700,fontSize:13,cursor:"pointer"}}>+ New Lead</button>
      </div>
      <div style={{display:"flex",gap:12,overflowX:"auto",paddingBottom:12,alignItems:"flex-start"}}>
        {STATUS_STAGES.map(stage=>{
          const stageleads=filtered.filter(l=>l.status===stage).sort((a,b)=>(b.sum||0)-(a.sum||0));
          const total=stageleads.reduce((s,l)=>s+(l.sum||0),0);
          return(
            <div key={stage} style={{minWidth:230,maxWidth:260,flex:"0 0 240px",background:"#f8fafc",borderRadius:12,overflow:"hidden",border:"1px solid #e2e8f0"}}>
              <div style={{padding:"12px 14px",background:STATUS_BADGE[stage],color:"#fff",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <div style={{fontWeight:700,fontSize:13}}>{stage}</div>
                <div style={{fontSize:12,opacity:0.9}}>{stageleads.length} · {fmtEur(total)}</div>
              </div>
              <div style={{padding:8,display:"flex",flexDirection:"column",gap:6,maxHeight:520,overflowY:"auto"}}>
                {stageleads.map(l=>(
                  <KanbanCard key={l.id} lead={l} stages={STATUS_STAGES} onMove={moveStatus} onClick={()=>onOpen(l)}/>
                ))}
                {stageleads.length===0&&<div style={{color:"#94a3b8",fontSize:12,textAlign:"center",padding:"16px 0"}}>No leads</div>}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function KanbanCard({lead,stages,onMove,onClick}){
  const [showMenu,setShowMenu]=useState(false);
  const ref=useRef();
  useEffect(()=>{
    const handler=(e)=>{if(ref.current&&!ref.current.contains(e.target))setShowMenu(false);};
    document.addEventListener("mousedown",handler);
    return()=>document.removeEventListener("mousedown",handler);
  },[]);
  const days=daysUntil(lead.dueDate);
  const overdueFlag=isOverdue(lead.dueDate);
  return(
    <div ref={ref} style={{background:"#fff",borderRadius:8,padding:"10px 12px",cursor:"pointer",border:"1px solid #e2e8f0",transition:"box-shadow 0.15s",position:"relative"}} onClick={onClick} onMouseEnter={e=>e.currentTarget.style.boxShadow="0 2px 8px rgba(0,0,0,0.12)"} onMouseLeave={e=>e.currentTarget.style.boxShadow="none"}>
      <div style={{fontSize:12,fontWeight:700,color:"#1e293b",marginBottom:4,lineHeight:1.3}}>{lead.reference||lead.quoteNr||"—"}</div>
      <div style={{fontSize:11,color:"#64748b",marginBottom:6}}>{lead.client}</div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:11}}>
        <span style={{fontWeight:700,color:"#10b981"}}>{fmtEur(lead.sum)}</span>
        <span style={{background:"#f1f5f9",borderRadius:4,padding:"2px 6px",fontSize:10,color:"#64748b"}}>{lead.poultry}</span>
      </div>
      <div style={{display:"flex",justifyContent:"space-between",marginTop:6,fontSize:10,color:"#94a3b8"}}>
        <span>{lead.rsm?.split(" ").slice(0,2).join(" ")}</span>
        {lead.dueDate&&<span style={{color:overdueFlag?"#ef4444":days<7?"#f59e0b":"#94a3b8"}}>{overdueFlag?`${Math.abs(days)}d overdue`:days<7?`${days}d left`:lead.dueDate?.slice(5)}</span>}
      </div>
      <div style={{marginTop:6,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div style={{height:4,flex:1,background:"#f1f5f9",borderRadius:2,marginRight:8}}><div style={{height:4,borderRadius:2,background:"#3b82f6",width:`${(lead.likelihood||0)*100}%`}}/></div>
        <span style={{fontSize:10,color:"#64748b"}}>{Math.round((lead.likelihood||0)*100)}%</span>
        <div style={{position:"relative",marginLeft:6}} onClick={e=>e.stopPropagation()}>
          <button onClick={e=>{e.stopPropagation();setShowMenu(!showMenu);}} style={{background:"#f1f5f9",border:"none",borderRadius:4,padding:"2px 6px",cursor:"pointer",fontSize:10,color:"#64748b",fontWeight:700}}>↕</button>
          {showMenu&&<div style={{position:"absolute",right:0,top:"100%",background:"#fff",boxShadow:"0 4px 12px rgba(0,0,0,0.15)",borderRadius:8,zIndex:100,minWidth:140,padding:4}}>
            {stages.filter(s=>s!==lead.status).map(s=><button key={s} onClick={()=>{onMove(lead,s);setShowMenu(false);}} style={{display:"block",width:"100%",textAlign:"left",padding:"6px 12px",background:"none",border:"none",cursor:"pointer",fontSize:12,color:"#1e293b",borderRadius:4}} onMouseEnter={e=>e.target.style.background="#f8fafc"} onMouseLeave={e=>e.target.style.background="none"}>→ {s}</button>)}
          </div>}
        </div>
      </div>
    </div>
  );
}

// ─── Leads Table ──────────────────────────────────────────────────────────────
function LeadsTable({leads,onOpen,currentUser}){
  const [search,setSearch]=useState("");
  const [filterRSM,setFilterRSM]=useState("");
  const [filterStatus,setFilterStatus]=useState("");
  const [filterPoultry,setFilterPoultry]=useState("");
  const [sort,setSort]=useState({col:"dueDate",dir:1});
  const [page,setPage]=useState(0);
  const PAGE=50;

  const filtered=useMemo(()=>{
    let r=leads;
    if(filterRSM)r=r.filter(l=>l.rsm===filterRSM);
    if(filterStatus)r=r.filter(l=>l.status===filterStatus);
    if(filterPoultry)r=r.filter(l=>l.poultry===filterPoultry);
    if(search){
      const q=search.toLowerCase();
      r=r.filter(l=>(l.reference||"").toLowerCase().includes(q)||(l.quoteNr||"").toLowerCase().includes(q)||(l.client||"").toLowerCase().includes(q)||(l.notes||"").toLowerCase().includes(q));
    }
    r=[...r].sort((a,b)=>{
      let av=a[sort.col]??0,bv=b[sort.col]??0;
      if(typeof av==="string")av=av.toLowerCase();
      if(typeof bv==="string")bv=bv.toLowerCase();
      return av<bv?-sort.dir:av>bv?sort.dir:0;
    });
    return r;
  },[leads,search,filterRSM,filterStatus,filterPoultry,sort]);

  const page_data=filtered.slice(page*PAGE,(page+1)*PAGE);
  const total_pages=Math.ceil(filtered.length/PAGE);

  const th=(col,label)=>(
    <th onClick={()=>setSort(s=>s.col===col?{col,dir:-s.dir}:{col,dir:1})} style={{padding:"10px 12px",textAlign:"left",fontSize:12,fontWeight:700,color:"#64748b",cursor:"pointer",userSelect:"none",whiteSpace:"nowrap",background:"#f8fafc",position:"sticky",top:0,borderBottom:"2px solid #e2e8f0"}}>
      {label}{sort.col===col?sort.dir===1?" ↑":" ↓":""}
    </th>
  );

  return(
    <div style={{display:"flex",flexDirection:"column",height:"calc(100vh - 104px)"}}>
      <div style={{display:"flex",gap:10,marginBottom:16,flexWrap:"wrap",alignItems:"center"}}>
        <h2 style={{fontSize:22,fontWeight:800,margin:0,marginRight:8}}>Leads</h2>
        <input value={search} onChange={e=>{setSearch(e.target.value);setPage(0);}} style={{padding:"7px 12px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,width:200,outline:"none"}} placeholder="Search reference, client…"/>
        <select value={filterRSM} onChange={e=>{setFilterRSM(e.target.value);setPage(0);}} style={{padding:"7px 12px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,background:"#fff",color:"#1e293b"}}>
          <option value="">All RSMs</option>
          {RSM_LIST.map(r=><option key={r}>{r}</option>)}
        </select>
        <select value={filterStatus} onChange={e=>{setFilterStatus(e.target.value);setPage(0);}} style={{padding:"7px 12px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,background:"#fff",color:"#1e293b"}}>
          <option value="">All Statuses</option>
          {STATUS_STAGES.map(s=><option key={s}>{s}</option>)}
        </select>
        <select value={filterPoultry} onChange={e=>{setFilterPoultry(e.target.value);setPage(0);}} style={{padding:"7px 12px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,background:"#fff",color:"#1e293b"}}>
          <option value="">All Poultry</option>
          {POULTRY_TYPES.map(p=><option key={p}>{p}</option>)}
        </select>
        <div style={{flex:1}}/>
        <span style={{fontSize:13,color:"#64748b"}}>{filtered.length} leads</span>
        <button onClick={()=>onOpen(null)} style={{background:"#3b82f6",color:"#fff",border:"none",borderRadius:8,padding:"8px 16px",fontWeight:700,fontSize:13,cursor:"pointer"}}>+ New Lead</button>
      </div>
      <div style={{flex:1,overflow:"auto",borderRadius:12,boxShadow:"0 1px 4px rgba(0,0,0,0.07)"}}>
        <table style={{width:"100%",borderCollapse:"collapse",background:"#fff",fontSize:13}}>
          <thead>
            <tr>
              {th("dueDate","Due")}{th("reference","Reference")}{th("client","Client")}{th("rsm","RSM")}{th("poultry","Poultry")}{th("sum","Value (€)")}{th("margin","Margin")}{th("status","Status")}{th("likelihood","Likely")}
              <th style={{padding:"10px 12px",background:"#f8fafc",borderBottom:"2px solid #e2e8f0",position:"sticky",top:0}}></th>
            </tr>
          </thead>
          <tbody>
            {page_data.map((l,i)=>{
              const overdue=isOverdue(l.dueDate);
              return(
                <tr key={l.id} style={{background:i%2===0?"#fff":"#f8fafc",cursor:"pointer"}} onClick={()=>onOpen(l)} onMouseEnter={e=>e.currentTarget.style.background="#eff6ff"} onMouseLeave={e=>e.currentTarget.style.background=i%2===0?"#fff":"#f8fafc"}>
                  <td style={{padding:"9px 12px",color:overdue?"#ef4444":"#64748b",whiteSpace:"nowrap",borderBottom:"1px solid #f1f5f9"}}>{l.dueDate||"—"}</td>
                  <td style={{padding:"9px 12px",fontWeight:600,color:"#1e293b",maxWidth:180,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",borderBottom:"1px solid #f1f5f9"}} title={l.reference}>{l.reference||"—"}</td>
                  <td style={{padding:"9px 12px",color:"#475569",maxWidth:160,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",borderBottom:"1px solid #f1f5f9"}} title={l.client}>{l.client}</td>
                  <td style={{padding:"9px 12px",color:"#475569",whiteSpace:"nowrap",borderBottom:"1px solid #f1f5f9"}}>{l.rsm?.split(" ").slice(0,2).join(" ")}</td>
                  <td style={{padding:"9px 12px",color:"#475569",borderBottom:"1px solid #f1f5f9"}}>{l.poultry}</td>
                  <td style={{padding:"9px 12px",fontWeight:700,color:"#10b981",textAlign:"right",borderBottom:"1px solid #f1f5f9"}}>{fmtEur(l.sum)}</td>
                  <td style={{padding:"9px 12px",textAlign:"right",borderBottom:"1px solid #f1f5f9"}}>{fmtPct(l.margin)}</td>
                  <td style={{padding:"9px 12px",borderBottom:"1px solid #f1f5f9"}}><span style={{background:STATUS_BADGE[l.status]+"22",color:STATUS_BADGE[l.status],borderRadius:6,padding:"3px 8px",fontSize:11,fontWeight:700}}>{l.status}</span></td>
                  <td style={{padding:"9px 12px",borderBottom:"1px solid #f1f5f9"}}><div style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:50,height:4,background:"#f1f5f9",borderRadius:2}}><div style={{height:4,borderRadius:2,background:"#3b82f6",width:`${(l.likelihood||0)*100}%`}}/></div><span style={{fontSize:11,color:"#64748b"}}>{Math.round((l.likelihood||0)*100)}%</span></div></td>
                  <td style={{padding:"9px 12px",borderBottom:"1px solid #f1f5f9"}}><span style={{color:"#3b82f6",fontSize:18}}>›</span></td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      {total_pages>1&&<div style={{display:"flex",justifyContent:"center",gap:8,marginTop:16,alignItems:"center"}}>
        <button onClick={()=>setPage(p=>Math.max(0,p-1))} disabled={page===0} style={{padding:"6px 12px",borderRadius:8,border:"1px solid #e2e8f0",background:"#fff",cursor:"pointer",fontSize:13,color:"#1e293b"}}>← Prev</button>
        <span style={{fontSize:13,color:"#64748b"}}>{page+1} / {total_pages}</span>
        <button onClick={()=>setPage(p=>Math.min(total_pages-1,p+1))} disabled={page===total_pages-1} style={{padding:"6px 12px",borderRadius:8,border:"1px solid #e2e8f0",background:"#fff",cursor:"pointer",fontSize:13,color:"#1e293b"}}>Next →</button>
      </div>}
    </div>
  );
}

// ─── Tasks View ───────────────────────────────────────────────────────────────
function TasksView({leads,saveLeads,currentUser,onOpen}){
  const [filterRSM,setFilterRSM]=useState(currentUser.role==="user"&&currentUser.rsm?currentUser.rsm:"");
  const [showDone,setShowDone]=useState(false);
  const allTasks=useMemo(()=>{
    return leads.flatMap(lead=>(lead.tasks||[]).map(t=>({...t,leadId:lead.id,leadRef:lead.reference||lead.quoteNr,leadClient:lead.client,leadRSM:lead.rsm})));
  },[leads]);
  const filtered=allTasks.filter(t=>{
    if(!showDone&&t.done)return false;
    if(filterRSM&&t.leadRSM!==filterRSM)return false;
    return true;
  }).sort((a,b)=>{
    if(a.done!==b.done)return a.done?1:-1;
    if(!a.dueDate&&!b.dueDate)return 0;
    if(!a.dueDate)return 1;
    if(!b.dueDate)return -1;
    return new Date(a.dueDate)-new Date(b.dueDate);
  });

  const toggleTask=(leadId,taskId)=>{
    saveLeads(leads.map(l=>l.id===leadId?{...l,tasks:l.tasks.map(t=>t.id===taskId?{...t,done:!t.done}:t)}:l));
  };

  return(
    <div style={{maxWidth:800}}>
      <div style={{display:"flex",gap:12,marginBottom:20,alignItems:"center"}}>
        <h2 style={{fontSize:22,fontWeight:800,margin:0}}>Tasks</h2>
        <div style={{flex:1}}/>
        <select value={filterRSM} onChange={e=>setFilterRSM(e.target.value)} style={{padding:"7px 12px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,background:"#fff",color:"#1e293b"}}>
          <option value="">All RSMs</option>
          {RSM_LIST.map(r=><option key={r}>{r}</option>)}
        </select>
        <label style={{display:"flex",alignItems:"center",gap:6,fontSize:13,color:"#64748b",cursor:"pointer"}}>
          <input type="checkbox" checked={showDone} onChange={e=>setShowDone(e.target.checked)}/> Show completed
        </label>
      </div>
      {filtered.length===0?<div style={{background:"#fff",borderRadius:12,padding:40,textAlign:"center",color:"#94a3b8",boxShadow:"0 1px 4px rgba(0,0,0,0.07)"}}>No tasks to show. Open a lead to add tasks.</div>:
      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {filtered.map(t=>{
          const days=daysUntil(t.dueDate);
          const overdue=!t.done&&isOverdue(t.dueDate);
          return(
            <div key={t.id} style={{background:"#fff",borderRadius:10,padding:"12px 16px",boxShadow:"0 1px 4px rgba(0,0,0,0.05)",display:"flex",alignItems:"flex-start",gap:12,opacity:t.done?0.6:1,border:overdue?"1px solid #fecaca":"1px solid #f1f5f9"}}>
              <input type="checkbox" checked={t.done||false} onChange={()=>toggleTask(t.leadId,t.id)} style={{marginTop:2,cursor:"pointer",width:16,height:16}}/>
              <div style={{flex:1}}>
                <div style={{fontSize:14,fontWeight:600,color:"#1e293b",textDecoration:t.done?"line-through":"none"}}>{t.text}</div>
                <div style={{fontSize:12,color:"#64748b",marginTop:4,display:"flex",gap:12}}>
                  <button onClick={()=>onOpen(leads.find(l=>l.id===t.leadId))} style={{background:"none",border:"none",color:"#3b82f6",cursor:"pointer",padding:0,fontSize:12,fontWeight:600}}>{t.leadRef}</button>
                  <span>·</span><span>{t.leadClient}</span>
                  {t.dueDate&&<><span>·</span><span style={{color:overdue?"#ef4444":days<3?"#f59e0b":"#64748b",fontWeight:overdue?700:400}}>{overdue?`Overdue ${Math.abs(days)}d`:days===0?"Today":days===1?"Tomorrow":`Due ${t.dueDate}`}</span></>}
                </div>
              </div>
              {t.dueDate&&<span style={{fontSize:11,color:"#94a3b8",whiteSpace:"nowrap"}}>{t.leadRSM?.split(" ").slice(0,2).join(" ")}</span>}
            </div>
          );
        })}
      </div>}
    </div>
  );
}

// ─── Settings View ────────────────────────────────────────────────────────────
function SettingsView({users,saveUsers,currentUser}){
  const [editUser,setEditUser]=useState(null);
  const [pwChange,setPwChange]=useState({});
  const updateUser=(id,field,val)=>saveUsers(users.map(u=>u.id===id?{...u,[field]:val}:u));
  return(
    <div style={{maxWidth:700}}>
      <h2 style={{fontSize:22,fontWeight:800,marginBottom:20}}>User Management</h2>
      <div style={{background:"#fff",borderRadius:12,boxShadow:"0 1px 4px rgba(0,0,0,0.07)",overflow:"hidden"}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
          <thead><tr style={{background:"#f8fafc",borderBottom:"2px solid #e2e8f0"}}>
            <th style={{padding:"10px 16px",textAlign:"left",fontWeight:700,color:"#64748b"}}>Username</th>
            <th style={{padding:"10px 16px",textAlign:"left",fontWeight:700,color:"#64748b"}}>Full Name</th>
            <th style={{padding:"10px 16px",textAlign:"left",fontWeight:700,color:"#64748b"}}>RSM</th>
            <th style={{padding:"10px 16px",textAlign:"left",fontWeight:700,color:"#64748b"}}>Role</th>
            <th style={{padding:"10px 16px",textAlign:"left",fontWeight:700,color:"#64748b"}}>Actions</th>
          </tr></thead>
          <tbody>
            {users.map((u,i)=>(
              <tr key={u.id} style={{borderBottom:"1px solid #f1f5f9",background:i%2===0?"#fff":"#f8fafc"}}>
                <td style={{padding:"10px 16px",fontWeight:600,fontFamily:"monospace"}}>{u.username}</td>
                <td style={{padding:"10px 16px"}}>
                  {editUser===u.id?<input value={u.fullName} onChange={e=>updateUser(u.id,"fullName",e.target.value)} style={{padding:"4px 8px",borderRadius:6,border:"1px solid #e2e8f0",fontSize:13,width:130}}/>:u.fullName}
                </td>
                <td style={{padding:"10px 16px"}}>
                  {editUser===u.id?<select value={u.rsm} onChange={e=>updateUser(u.id,"rsm",e.target.value)} style={{padding:"4px 8px",borderRadius:6,border:"1px solid #e2e8f0",fontSize:12,background:"#fff"}}>
                    <option value="">—</option>{RSM_LIST.map(r=><option key={r}>{r}</option>)}
                  </select>:<span style={{fontSize:12,color:"#64748b"}}>{u.rsm||"—"}</span>}
                </td>
                <td style={{padding:"10px 16px"}}>
                  {editUser===u.id?<select value={u.role} onChange={e=>updateUser(u.id,"role",e.target.value)} style={{padding:"4px 8px",borderRadius:6,border:"1px solid #e2e8f0",fontSize:12,background:"#fff"}}>
                    <option value="user">user</option><option value="admin">admin</option>
                  </select>:<span style={{background:u.role==="admin"?"#fef3c7":"#f1f5f9",color:u.role==="admin"?"#92400e":"#64748b",borderRadius:6,padding:"2px 8px",fontSize:11,fontWeight:600}}>{u.role}</span>}
                </td>
                <td style={{padding:"10px 16px",display:"flex",gap:8,alignItems:"center"}}>
                  {editUser===u.id?(
                    <>
                      <input value={pwChange[u.id]||""} onChange={e=>setPwChange(p=>({...p,[u.id]:e.target.value}))} style={{padding:"4px 8px",borderRadius:6,border:"1px solid #e2e8f0",fontSize:12,width:110}} placeholder="New password" type="password"/>
                      <button onClick={()=>{
                        if(pwChange[u.id])saveUsers(users.map(x=>x.id===u.id?{...x,password:simpleHash(pwChange[u.id])}:x));
                        setEditUser(null);setPwChange(p=>({...p,[u.id]:""}));
                      }} style={{background:"#10b981",color:"#fff",border:"none",borderRadius:6,padding:"4px 10px",fontSize:12,cursor:"pointer",fontWeight:600}}>Save</button>
                      <button onClick={()=>setEditUser(null)} style={{background:"#f1f5f9",border:"none",borderRadius:6,padding:"4px 10px",fontSize:12,cursor:"pointer"}}>Cancel</button>
                    </>
                  ):<button onClick={()=>setEditUser(u.id)} style={{background:"#f1f5f9",border:"none",borderRadius:6,padding:"4px 10px",fontSize:12,cursor:"pointer",color:"#475569",fontWeight:600}}>Edit</button>}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div style={{marginTop:16,padding:16,background:"#fff",borderRadius:12,boxShadow:"0 1px 4px rgba(0,0,0,0.07)",fontSize:13,color:"#64748b"}}>
        <strong style={{color:"#1e293b"}}>Note:</strong> Passwords are stored with a simple hash for this browser-based prototype. For production use, connect a proper backend authentication service.
      </div>
    </div>
  );
}

// ─── Lead Modal ───────────────────────────────────────────────────────────────
function LeadModal({lead,onSave,onClose,onDelete,currentUser}){
  const [data,setData]=useState({...lead});
  const [activeTab,setActiveTab]=useState("basic");
  const [newTask,setNewTask]=useState({text:"",dueDate:""});
  const isNew=!lead.createdAt||lead.tasks===undefined||SEED_LEADS.some(x=>x.id!==lead.id)&&lead.id?.startsWith("seed_")===false&&!lead.id?.startsWith("seed_");
  const set=(k,v)=>setData(d=>({...d,[k]:v}));
  const addTask=()=>{
    if(!newTask.text.trim())return;
    const t={id:uid(),text:newTask.text,dueDate:newTask.dueDate,done:false,createdBy:currentUser.fullName,createdAt:new Date().toISOString()};
    setData(d=>({...d,tasks:[...(d.tasks||[]),t]}));
    setNewTask({text:"",dueDate:""});
  };
  const toggleTask=(id)=>setData(d=>({...d,tasks:d.tasks.map(t=>t.id===id?{...t,done:!t.done}:t)}));
  const deleteTask=(id)=>setData(d=>({...d,tasks:d.tasks.filter(t=>t.id!==id)}));
  const addNote=(text)=>{
    if(!text.trim())return;
    const e={id:uid(),text,user:currentUser.fullName,timestamp:new Date().toISOString(),type:"note"};
    setData(d=>({...d,activityLog:[...(d.activityLog||[]),e]}));
  };

  const inp=(k,label,opts={})=>(
    <div style={{marginBottom:14}}>
      <label style={{display:"block",fontSize:12,fontWeight:700,color:"#64748b",marginBottom:5,textTransform:"uppercase",letterSpacing:0.5}}>{label}</label>
      {opts.textarea?<textarea value={data[k]||""} onChange={e=>set(k,e.target.value)} rows={3} style={{width:"100%",boxSizing:"border-box",padding:"8px 10px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,resize:"vertical",fontFamily:"inherit",outline:"none"}}/>:
       opts.select?<select value={data[k]||""} onChange={e=>set(k,e.target.value)} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,background:"#fff",outline:"none",color:"#1e293b"}}>
        {(opts.options||[]).map(o=><option key={o} value={o}>{o||"—"}</option>)}
       </select>:
       <input type={opts.type||"text"} value={data[k]||""} onChange={e=>set(k,e.target.value)} style={{width:"100%",boxSizing:"border-box",padding:"8px 10px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,outline:"none"}}/>}
    </div>
  );

  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",display:"flex",alignItems:"flex-start",justifyContent:"center",padding:24,zIndex:1000,overflowY:"auto"}} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{background:"#fff",borderRadius:16,width:"100%",maxWidth:800,boxShadow:"0 24px 60px rgba(0,0,0,0.25)",marginTop:24,marginBottom:24}}>
        {/* Header */}
        <div style={{padding:"20px 24px",borderBottom:"1px solid #f1f5f9",display:"flex",alignItems:"center",gap:12}}>
          <div style={{flex:1}}>
            <div style={{fontSize:18,fontWeight:800,color:"#1e293b"}}>{data.reference||"New Lead"}</div>
            <div style={{fontSize:13,color:"#64748b",marginTop:2}}>{data.client}{data.quoteNr&&` · ${data.quoteNr}`}</div>
          </div>
          <span style={{background:STATUS_BADGE[data.status]+"22",color:STATUS_BADGE[data.status],borderRadius:8,padding:"4px 12px",fontSize:12,fontWeight:700}}>{data.status}</span>
          <button onClick={onClose} style={{background:"none",border:"none",color:"#94a3b8",fontSize:20,cursor:"pointer",padding:"4px 8px"}}>✕</button>
        </div>
        {/* Tabs */}
        <div style={{display:"flex",gap:0,borderBottom:"1px solid #f1f5f9",padding:"0 24px"}}>
          {[["basic","📋 Details"],["equipment","🔧 Equipment"],["tasks","✅ Tasks"],["log","📝 Notes"]].map(([id,label])=>(
            <button key={id} onClick={()=>setActiveTab(id)} style={{background:"none",border:"none",borderBottom:activeTab===id?"2px solid #3b82f6":"2px solid transparent",color:activeTab===id?"#3b82f6":"#64748b",padding:"12px 16px",cursor:"pointer",fontSize:13,fontWeight:600,marginBottom:-1}}>
              {label}
            </button>
          ))}
        </div>
        {/* Tab Content */}
        <div style={{padding:"20px 24px",maxHeight:"calc(70vh - 140px)",overflowY:"auto"}}>
          {activeTab==="basic"&&(
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
              <div>{inp("quoteNr","Quote Nr")}{inp("reference","Reference / Project Name")}{inp("client","Client")}{inp("country","Country")}</div>
              <div>
                {inp("version","Version",{select:true,options:VERSIONS})}
                {inp("rsm","RSM",{select:true,options:["","...RSM",...RSM_LIST]})}
                {inp("poultry","Poultry Type",{select:true,options:POULTRY_TYPES})}
                {inp("status","Status",{select:true,options:STATUS_STAGES})}
              </div>
              <div>{inp("sum","Project Value (€)",{type:"number"})}{inp("margin","Margin (0.xx)",{type:"number"})}</div>
              <div>
                <div style={{marginBottom:14}}>
                  <label style={{display:"block",fontSize:12,fontWeight:700,color:"#64748b",marginBottom:5,textTransform:"uppercase",letterSpacing:0.5}}>Likelihood ({Math.round((data.likelihood||0)*100)}%)</label>
                  <input type="range" min="0" max="1" step="0.1" value={data.likelihood||0} onChange={e=>set("likelihood",parseFloat(e.target.value))} style={{width:"100%"}}/>
                </div>
                {inp("dueDate","Due Date",{type:"date"})}{inp("date","Quote Date",{type:"date"})}
              </div>
              <div style={{gridColumn:"1/-1"}}>{inp("notes","Notes")}{inp("manage","Internal Notes / Manage")}</div>
            </div>
          )}
          {activeTab==="equipment"&&(
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12}}>
              {[["feeding1","Feeding 1"],["feeding2","Feeding 2"],["watering","Watering"],["controls","Controls"],["birdWeighing","Bird Weighing"],["flexAuger1","Flex Auger 1"],["flexAuger2","Flex Auger 2"],["silo1","Silo 1"],["silo2","Silo 2"],["ventilation","Ventilation"],["padCooling","Pad Cooling"],["feedWeighing","Feed Weighing"],["heating","Heating"],["aviary","Aviary"],["cage","Cage"],["nest","Nest"]].map(([k,label])=>(
                <div key={k} style={{marginBottom:10}}>
                  <label style={{display:"block",fontSize:11,fontWeight:700,color:"#64748b",marginBottom:4,textTransform:"uppercase",letterSpacing:0.5}}>{label}</label>
                  <select value={data[k]||""} onChange={e=>set(k,e.target.value)} style={{width:"100%",padding:"7px 10px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,background:"#fff",color:"#1e293b",outline:"none"}}>
                    {(EQUIPMENT[k]||[""]).map(o=><option key={o} value={o}>{o||"—"}</option>)}
                  </select>
                </div>
              ))}
            </div>
          )}
          {activeTab==="tasks"&&(
            <div>
              <div style={{display:"flex",gap:8,marginBottom:20}}>
                <input value={newTask.text} onChange={e=>setNewTask(p=>({...p,text:e.target.value}))} onKeyDown={e=>e.key==="Enter"&&addTask()} style={{flex:1,padding:"8px 12px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,outline:"none"}} placeholder="Add task…"/>
                <input type="date" value={newTask.dueDate} onChange={e=>setNewTask(p=>({...p,dueDate:e.target.value}))} style={{padding:"8px 12px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,outline:"none"}}/>
                <button onClick={addTask} style={{background:"#3b82f6",color:"#fff",border:"none",borderRadius:8,padding:"8px 16px",fontWeight:700,fontSize:13,cursor:"pointer"}}>Add</button>
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {(data.tasks||[]).map(t=>(
                  <div key={t.id} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",background:"#f8fafc",borderRadius:8,opacity:t.done?0.6:1}}>
                    <input type="checkbox" checked={t.done||false} onChange={()=>toggleTask(t.id)} style={{cursor:"pointer"}}/>
                    <div style={{flex:1}}>
                      <div style={{fontSize:14,color:"#1e293b",textDecoration:t.done?"line-through":"none"}}>{t.text}</div>
                      <div style={{fontSize:11,color:"#94a3b8",marginTop:2}}>{t.createdBy} · {t.dueDate||"No due date"}</div>
                    </div>
                    <button onClick={()=>deleteTask(t.id)} style={{background:"none",border:"none",color:"#ef4444",cursor:"pointer",fontSize:16,padding:"0 4px"}}>✕</button>
                  </div>
                ))}
                {(data.tasks||[]).length===0&&<div style={{color:"#94a3b8",fontSize:13,textAlign:"center",padding:20}}>No tasks yet. Add one above!</div>}
              </div>
            </div>
          )}
          {activeTab==="log"&&(
            <div>
              <NoteInput onAdd={addNote}/>
              <div style={{display:"flex",flexDirection:"column",gap:8,marginTop:16}}>
                {[...(data.activityLog||[])].reverse().map(e=>(
                  <div key={e.id} style={{padding:"10px 14px",background:"#f8fafc",borderRadius:8,borderLeft:"3px solid #3b82f6"}}>
                    <div style={{fontSize:14,color:"#1e293b"}}>{e.text}</div>
                    <div style={{fontSize:11,color:"#94a3b8",marginTop:4}}>{e.user} · {new Date(e.timestamp).toLocaleDateString("en-GB",{day:"2-digit",month:"short",year:"numeric"})}</div>
                  </div>
                ))}
                {(data.activityLog||[]).length===0&&<div style={{color:"#94a3b8",fontSize:13,textAlign:"center",padding:20}}>No notes yet.</div>}
              </div>
            </div>
          )}
        </div>
        {/* Footer */}
        <div style={{padding:"16px 24px",borderTop:"1px solid #f1f5f9",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <button onClick={()=>onDelete(data.id)} style={{background:"none",border:"1px solid #fecaca",color:"#ef4444",borderRadius:8,padding:"8px 16px",fontSize:13,cursor:"pointer",fontWeight:600}}>Delete Lead</button>
          <div style={{display:"flex",gap:10}}>
            <button onClick={onClose} style={{background:"#f1f5f9",border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,cursor:"pointer",color:"#475569",fontWeight:600}}>Cancel</button>
            <button onClick={()=>onSave(data)} style={{background:"#3b82f6",color:"#fff",border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,cursor:"pointer",fontWeight:700}}>Save Lead</button>
          </div>
        </div>
      </div>
    </div>
  );
}

function NoteInput({onAdd}){
  const [text,setText]=useState("");
  return(
    <div style={{display:"flex",gap:8}}>
      <input value={text} onChange={e=>setText(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&text.trim()){onAdd(text);setText("");}}} style={{flex:1,padding:"8px 12px",borderRadius:8,border:"1px solid #e2e8f0",fontSize:13,outline:"none"}} placeholder="Add note / activity…"/>
      <button onClick={()=>{if(text.trim()){onAdd(text);setText("");}}} style={{background:"#3b82f6",color:"#fff",border:"none",borderRadius:8,padding:"8px 16px",fontWeight:700,fontSize:13,cursor:"pointer"}}>Add</button>
    </div>
  );
}
